import java.util.Scanner;

public class SecureBufferHandling {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string (up to 10 characters):");
        String input = scanner.nextLine();

        // Ensure input length does not exceed buffer size
        if (input.length() > 10) {
            System.out.println("Input exceeds buffer size limit.");
            return;
        }

        // Create a fixed-size buffer with sufficient capacity
        char[] buffer = new char[10];

        // Copy user input into the buffer with boundary checking
        for (int i = 0; i < input.length(); i++) {
            if (i < buffer.length) {
                buffer[i] = input.charAt(i);
            }
        }

        System.out.println("Input successfully stored in buffer: " + new String(buffer).trim());
    }
}

